<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop Environment</title>
    <style>
        :root {
            --bg-color: #2c2c2c;
            --taskbar-bg: rgba(40, 40, 40, 0.95);
            --window-header: #383838;
            --window-content: #2e2e2e;
            --accent-color: #E95420; /* Ubuntu Orange */
            --text-color: #eeeeee;
            --border-color: #1a1a1a;
        }

        * { box-sizing: border-box; user-select: none; }

        body, html {
            margin: 0; padding: 0; width: 100%; height: 100%; overflow: hidden;
            font-family: 'Ubuntu', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
            background-color: #1a1a1a;
        }

        /* Desktop */
        #desktop {
            width: 100%; height: 100%;
            position: relative;
            background: linear-gradient(135deg, #2c3e50 0%, #000000 100%); /* Dark wallpaper */
            overflow: hidden;
        }

        /* Taskbar / Dock */
        #taskbar {
            position: absolute;
            bottom: 10px;
            left: 50%;
            transform: translateX(-50%);
            background: rgba(30, 30, 30, 0.9);
            border-radius: 8px;
            padding: 8px 12px;
            display: flex;
            gap: 10px;
            box-shadow: 0 4px 15px rgba(0,0,0,0.5);
            z-index: 1000;
        }

        .launcher {
            background-color: #4a4a4a;
            border: none;
            color: white;
            padding: 8px 16px;
            border-radius: 4px;
            cursor: pointer;
            font-size: 14px;
            transition: background 0.2s, transform 0.1s;
        }

        .launcher:hover { background-color: #5a5a5a; }
        .launcher:active { transform: scale(0.98); }

        /* Windows */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background-color: var(--window-content);
            border-radius: 6px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.6);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #444;
        }

        .window-header {
            background-color: var(--window-header);
            padding: 8px 12px;
            cursor: move; /* Draggable-looking */
            display: flex;
            justify-content: space-between;
            align-items: center;
            user-select: none;
        }

        .window-title { font-weight: bold; color: #ddd; pointer-events: none;}

        .win-close {
            background-color: #e74c3c;
            width: 12px; height: 12px;
            border-radius: 50%;
            cursor: pointer;
            margin-left: 8px;
            display: inline-block;
        }

        .window-content {
            flex: 1;
            padding: 10px;
            overflow: auto;
            color: var(--text-color);
            position: relative;
        }

        /* Files App Specifics */
        #files-path-bar {
            display: flex;
            gap: 8px;
            margin-bottom: 10px;
            background: #222;
            padding: 5px;
            border-radius: 4px;
            align-items: center;
        }

        #files-up {
            background: #444; color: white; border: none; padding: 2px 8px; cursor: pointer; border-radius: 3px;
        }

        #files-path {
            flex: 1;
            background: transparent;
            border: none;
            color: #ddd;
            font-family: inherit;
            outline: none;
            text-align: center;
        }

        .fs-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
            gap: 15px;
            align-content: start;
        }

        .fs-item {
            background-color: #3a3a3a;
            border: 1px solid #444;
            padding: 10px;
            text-align: center;
            border-radius: 4px;
            cursor: pointer;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 80px;
        }

        .fs-item:hover { background-color: #4a4a4a; border-color: var(--accent-color); }
        .fs-item span { font-size: 12px; word-break: break-word; text-align: center;}

        /* Notepad Specifics */
        #notepad-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 5px;}
        #tabs {
            display: flex;
            gap: 5px;
            overflow-x: auto;
            background: #222;
            padding: 5px;
            border-radius: 4px;
            min-height: 30px;
        }

        .tab {
            background-color: #444;
            color: #ccc;
            padding: 4px 10px;
            border-radius: 4px 4px 0 0;
            cursor: pointer;
            font-size: 12px;
            white-space: nowrap;
        }

        .tab.active { background-color: var(--accent-color); color: white; }

        #new-tab-btn {
            margin-top: 5px;
            padding: 4px 8px;
            font-size: 12px;
            cursor: pointer;
            background: #444; border: none; color: white; border-radius: 3px;
        }

        #editor {
            width: 100%; height: calc(100% - 60px); /* Adjust based on header */
            background-color: #2e2e2e;
            color: #eee;
            border: none;
            resize: none;
            font-family: monospace;
            padding: 10px;
            outline: none;
        }

        /* Hidden utility */
        .hidden { display: none !important; }

    </style>
</head>
<body>

<div id="desktop">

    <!-- Windows -->

    <!-- Files Window -->
    <div id="files-window" class="window hidden" style="top: 50px; left: 100px; width: 600px;">
        <div class="window-header">
            <span class="window-title">Files</span>
            <div class="win-close"></div>
        </div>
        <div class="window-content" style="display:flex; flex-direction:column; height:100%;">
            <div id="files-path-bar">
                <button id="files-up">↑ Up</button>
                <input type="text" id="files-path" readonly value="/">
            </div>
            <div id="fs-list" class="fs-grid">
                <!-- Items injected here -->
            </div>
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window hidden" style="top: 80px; left: 200px; width: 500px;">
        <div class="window-header">
            <span class="window-title">Notepad</span>
            <div class="win-close"></div>
        </div>
        <div class="window-content" style="display:flex; flex-direction:column; height:100%;">
            <div id="notepad-header">
                <div id="tabs">
                    <!-- Tabs injected here -->
                </div>
                <button id="new-tab">#</button>
            </div>
            <textarea id="editor" placeholder="Start typing..."></textarea>
        </div>
    </div>

    <!-- Taskbar -->
    <div id="taskbar">
        <button id="open-files" class="launcher">Files</button>
        <button id="open-notepad" class="launcher">Notepad</button>
    </div>

</div>

<script>
    // --- File System Data ---
    const fileSystem = {
        "/": ["bin", "etc", "home", "usr", "var"],
        "/bin": [],
        "/etc": [],
        "/home": ["user"],
        "/home/user": ["Documents", "Downloads", "Pictures", "notes.txt"],
        "/usr": [],
        "/var": []
    };

    // --- State ---
    let currentPath = "/";
    let activeWindowZIndex = 10;

    // --- Notepad State & Persistence ---
    const LS_KEY = 'ubuntu_desktop_notepad_state';

    function loadNotepadState() {
        try {
            const saved = localStorage.getItem(LS_KEY);
            if (saved) return JSON.parse(saved);
        } catch (e) {}
        // Default State
        return {
            tabs: [{ id: 1, name: 'Untitled', content: '' }],
            activeId: 1
        };
    }

    let notepadState = loadNotepadState();

    function saveNotepadState() {
        localStorage.setItem(LS_KEY, JSON.stringify(notepadState));
    }

    // --- DOM Elements ---
    const desktop = document.getElementById('desktop');
    const filesWindow = document.getElementById('files-window');
    const notepadWindow = document.getElementById('notepad-window');

    const openFilesBtn = document.getElementById('open-files');
    const openNotepadBtn = document.getElementById('open-notepad');
    const closeButtons = document.querySelectorAll('.win-close');

    // Files App Elements
    const filesPathInput = document.getElementById('files-path');
    const filesUpBtn = document.getElementById('files-up');
    const fsList = document.getElementById('fs-list');

    // Notepad Elements
    const tabsContainer = document.getElementById('tabs');
    const newTabBtn = document.getElementById('new-tab');
    const editor = document.getElementById('editor');

    // --- Window Management ---
    function bringToFront(win) {
        activeWindowZIndex++;
        win.style.zIndex = activeWindowZIndex;
    }

    function toggleWindow(win, isOpeningFromLauncher) {
        if (win.classList.contains('hidden')) {
            win.classList.remove('hidden');
            bringToFront(win);
        } else {
            bringToFront(win);
        }
    }

    function hideWindow(win) {
        win.classList.add('hidden');
    }

    // Event Listeners for Launchers
    openFilesBtn.addEventListener('click', () => toggleWindow(filesWindow));
    openNotepadBtn.addEventListener('click', () => toggleWindow(notepadWindow));

    // Close Buttons
    closeButtons.forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation(); 
            const win = btn.closest('.window');
            hideWindow(win);
        });
    });

    // --- Files App Logic ---
    function renderFiles() {
        fsList.innerHTML = '';

        // Update Path Display
        filesPathInput.value = currentPath;

        const items = fileSystem[currentPath] || [];

        if (items.length === 0) {
            const emptyMsg = document.createElement('div');
            emptyMsg.textContent = "(Empty Folder)";
            emptyMsg.style.gridColumn = "1 / -1";
            emptyMsg.style.textAlign = "center";
            emptyMsg.style.color = "#888";
            fsList.appendChild(emptyMsg);
        } else {
            items.forEach(name => {
                const itemEl = document.createElement('div');
                itemEl.className = 'fs-item';

                // Check if it's a folder by seeing if path exists in FS keys
                const potentialPath = currentPath.endsWith('/') ? currentPath + name : currentPath + '/' + name;
                const isDir = fileSystem.hasOwnProperty(potentialPath);

                itemEl.innerHTML = `<span>${name}</span>`;

                // Double click to navigate
                itemEl.addEventListener('dblclick', () => {
                    if (isDir) {
                        currentPath = potentialPath;
                        renderFiles();
                    } else {
                        console.log("Opened file:", name);
                    }
                });

                fsList.appendChild(itemEl);
            });
        }
    }

    filesUpBtn.addEventListener('click', () => {
        if (currentPath === "/") return;

        const parts = currentPath.split('/').filter(p => p !== '');
        if (parts.length > 1) {
            parts.pop();
            currentPath = '/' + parts.join('/');
        } else {
            currentPath = '/';
        }
        renderFiles();
    });

    // --- Notepad App Logic ---
    function renderNotepad() {
        tabsContainer.innerHTML = '';

        notepadState.tabs.forEach(tab => {
            const tabEl = document.createElement('div');
            tabEl.className = `tab ${tab.id === notepadState.activeId ? 'active' : ''}`;
            tabEl.textContent = tab.name;

            tabEl.addEventListener('click', () => {
                notepadState.activeId = tab.id;
                editor.value = tab.content;
                renderNotepad(); 
                saveNotepadState();
            });

            tabsContainer.appendChild(tabEl);
        });

        const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeId);
        if (activeTab) {
            editor.value = activeTab.content;
        } else {
            editor.value = '';
        }
    }

    newTabBtn.addEventListener('click', () => {
        const newId = Date.now();
        notepadState.tabs.push({ id: newId, name: 'Untitled', content: '' });
        notepadState.activeId = newId;
        renderNotepad();
        saveNotepadState();
    });

    editor.addEventListener('input', (e) => {
        const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeId);
        if (activeTab) {
            activeTab.content = e.target.value;
            saveNotepadState();
        }
    });

    // --- Dragging Logic ---
    function makeDraggable(element) {
        let pos1 = 0, pos2 = 0, pos3 = 0, pos4 = 0;

        const header = element.querySelector('.window-header');
        if (!header) return;

        header.onmousedown = dragMouseDown;

        function dragMouseDown(e) {
            e.preventDefault();
            pos3 = e.clientX;
            pos4 = e.clientY;

            bringToFront(element);

            document.onmouseup = closeDragElement;
            document.onmousemove = elementDrag;
        }

        function elementDrag(e) {
            e.preventDefault();
            pos1 = pos3 - e.clientX;
            pos2 = pos4 - e.clientY;
            pos3 = e.clientX;
            pos4 = e.clientY;

            let top = (element.offsetTop - pos2);
            let left = (element.offsetLeft - pos1);

            if (top < 0) top = 0;
            if (left < 0) left = 0;

            element.style.top = top + "px";
            element.style.left = left + "px";
        }

        function closeDragElement() {
            document.onmouseup = null;
            document.onmousemove = null;
        }
    }

    makeDraggable(filesWindow);
    makeDraggable(notepadWindow);

    // --- Initialization ---
    renderFiles();
    renderNotepad();

</script>
</body>
</html>
